import type { ScenarioQuestion } from "./types";
type D = "beginner" | "intermediate" | "advanced";
function q(id: string, g: string, s: string, sc: string, qu: string, a: string, f: string, d: D): ScenarioQuestion {
  return { id, formatType: "scenario", categoryGroup: g, subcategory: s, scenarioPrompt: sc, question: qu, exampleAnswer: a, feedback: f, difficulty: d };
}
const ip = "interview_preparation", ws = "workplace_scenarios", ct = "clinical_transition", pd = "professional_development", cn = "career_navigation";

export const bulkGeneratedBatch15: ScenarioQuestion[] = [
  q("sq-bg15-1",ip,"clinical_judgment","A patient develops thrombotic thrombocytopenic purpura.","How would you recognize TTP?","TTP presents with the pentad: thrombocytopenia, microangiopathic hemolytic anemia (schistocytes on smear), neurological symptoms, renal dysfunction, and fever. Unlike HIT, TTP requires urgent plasmapheresis. Platelet transfusion is contraindicated as it can worsen thrombosis. ADAMTS13 activity is severely reduced in TTP.","TTP pentad with platelet transfusion contraindication.","advanced"),
  q("sq-bg15-2",ip,"clinical_judgment","A patient develops acute acalculous cholecystitis in the ICU.","What is acalculous cholecystitis?","Acalculous cholecystitis occurs without gallstones, typically in critically ill ICU patients from gallbladder ischemia and bile stasis. It presents with RUQ pain, fever, and leukocytosis. Ultrasound shows gallbladder distension and wall thickening without stones. Treatment is percutaneous cholecystostomy drainage or cholecystectomy. It carries higher mortality than calculous cholecystitis.","Acalculous cholecystitis in critical illness.","advanced"),
  q("sq-bg15-3",ip,"clinical_judgment","A patient develops posterior circulation stroke.","How does posterior stroke differ from anterior?","Posterior circulation strokes affect the brainstem and cerebellum, presenting with vertigo, diplopia, dysarthria, ataxia, and cranial nerve deficits rather than the typical hemiparesis and aphasia of anterior strokes. The symptoms can be subtle and easily mistaken for benign vertigo. FAST screening may miss posterior strokes—I would use BE-FAST which adds Balance and Eyes.","Posterior stroke BE-FAST recognition.","advanced"),
  q("sq-bg15-4",ip,"clinical_judgment","A patient develops contrast-induced nephropathy after cardiac catheterization.","How would you prevent contrast-induced nephropathy?","Prevention includes: adequate pre-hydration with IV normal saline, using low-osmolar or iso-osmolar contrast, minimizing contrast volume, holding metformin 48 hours after contrast, and monitoring creatinine 24-48 hours post-procedure. Risk factors include pre-existing CKD, diabetes, dehydration, and high contrast volume. N-acetylcysteine may be used though evidence is mixed.","Contrast nephropathy prevention protocol.","intermediate"),
  q("sq-bg15-5",ip,"clinical_judgment","A patient develops acute angle-closure glaucoma.","How would you recognize acute angle-closure glaucoma?","Acute angle-closure presents with sudden severe eye pain, headache, nausea and vomiting, halos around lights, and a fixed mid-dilated pupil. The eye is red with a hazy cornea and elevated intraocular pressure. This is an ophthalmologic emergency—delayed treatment causes permanent vision loss. I would avoid dilating drops and facilitate immediate ophthalmology consultation.","Acute glaucoma emergency recognition.","intermediate"),
  q("sq-bg15-6",ip,"clinical_judgment","A patient develops tumor lysis syndrome after chemotherapy.","How would you manage tumor lysis syndrome?","TLS causes hyperkalemia, hyperphosphatemia, hyperuricemia, and hypocalcemia from rapid tumor cell destruction. I would administer aggressive IV hydration, rasburicase or allopurinol for uric acid, monitor electrolytes every 6 hours, watch for cardiac arrhythmias from hyperkalemia, and ensure renal function is adequate. Prevention with hydration and rasburicase before chemo is preferred.","TLS electrolyte crisis management.","advanced"),
  q("sq-bg15-7",ip,"clinical_judgment","A patient develops acute adrenal insufficiency.","How would you recognize adrenal crisis?","Adrenal crisis presents with severe hypotension unresponsive to fluids and vasopressors, hyperkalemia, hyponatremia, hypoglycemia, and altered consciousness. Common triggers include abrupt steroid discontinuation, sepsis in patients with adrenal insufficiency, and bilateral adrenal hemorrhage. Treatment is immediate IV hydrocortisone 100mg bolus, then 50mg every 8 hours.","Adrenal crisis recognition with hydrocortisone.","advanced"),
  q("sq-bg15-8",ip,"clinical_judgment","A patient develops hypertensive emergency with papilledema.","How does hypertensive emergency differ from urgency?","Hypertensive emergency involves severe hypertension with acute target organ damage (encephalopathy, papilledema, acute MI, aortic dissection, pulmonary edema). Hypertensive urgency is severe hypertension without organ damage. Emergencies require IV antihypertensives with controlled reduction (25% in first hour). Urgencies can be managed with oral medications. Rapid reduction in emergencies can cause stroke.","Hypertensive emergency versus urgency with reduction rate.","advanced"),
  q("sq-bg15-9",ip,"behavioral","You are asked about maintaining motivation.","How do you stay motivated in challenging times?","I find motivation through connection to purpose—remembering why I chose nursing. Each patient interaction reinforces that purpose. On difficult days, I focus on small victories: the patient who smiled, the family member who felt heard, the clinical skill I mastered. Long-term motivation comes from continuous growth and meaningful human connection.","Purpose-driven motivation sustainability.","beginner"),
  q("sq-bg15-10",ip,"behavioral","You are asked how you handle uncertainty.","How do you manage clinical uncertainty?","I acknowledge uncertainty openly rather than masking it with false confidence. I use clinical reasoning frameworks, consult evidence-based resources, involve experienced colleagues, and communicate honestly when I do not have all the answers. Medical uncertainty is inherent in healthcare—managing it transparently protects patients better than pretending certainty.","Honest uncertainty management.","beginner"),
  q("sq-bg15-11",ip,"scenario_responses","A patient asks about complementary therapies.","How would you respond to complementary therapy questions?","I support an integrative approach: 'Many patients find complementary therapies helpful alongside their medical treatment. I would encourage you to discuss specific therapies with your physician, especially to ensure they do not interact with your medications. Techniques like guided imagery, deep breathing, and therapeutic touch are often safe and can help with comfort.'","Integrative therapy scope-appropriate response.","beginner"),
  q("sq-bg15-12",ip,"scenario_responses","A patient is worried about hospital-acquired infections.","How would you address HAI concerns?","I would validate and educate: 'Your concern is justified—hospital-acquired infections are something we take very seriously. You can see that I wash my hands every time I enter your room, we clean all equipment between patients, and your central line care follows strict sterile protocols. Please remind anyone who enters your room to wash their hands.'","HAI patient empowerment.","beginner"),
  q("sq-bg15-13",ip,"star_examples","Describe a time you improved a process.","Share a process improvement example.","I noticed that medication reconciliation on admission was inconsistent, with nurses using different approaches. I created a standardized medication reconciliation checklist based on best practices, piloted it with willing colleagues, collected feedback, and presented it to the unit educator. The tool was adopted unit-wide and reduced reconciliation errors by 30% in the first month.","Process improvement with measurable impact.","intermediate"),
  q("sq-bg15-14",ws,"prioritization","You have a patient with stroke symptoms and another requesting pain medication.","How would you prioritize stroke versus pain medication?","Stroke is immediately life-threatening—time is brain. I would activate the stroke code immediately, assess using the NIH Stroke Scale, ensure CT is obtained within 25 minutes, and stay with the stroke patient through the acute phase. I would ask a colleague to address the pain medication request and communicate the delay to the other patient.","Stroke code activation priority.","beginner"),
  q("sq-bg15-15",ws,"prioritization","A patient is hypoglycemic and another has a concerning oxygen saturation.","How would you prioritize hypoglycemia versus hypoxia?","Both are urgent. I would assess which is more immediately life-threatening: if SpO2 is in the 80s, oxygen takes priority as hypoxia can cause cardiac arrest within minutes. If SpO2 is low 90s, I would treat hypoglycemia first as it is faster to correct (give glucose) and then address oxygen. Rapid assessment of severity guides the sequence.","Severity-based dual-urgent prioritization.","intermediate"),
  q("sq-bg15-16",ws,"delegation","You need to delegate monitoring a patient receiving a blood transfusion.","How would you delegate blood transfusion monitoring?","I cannot delegate the initial verification and first 15-minute assessment—these are RN responsibilities. After the first 15 minutes, I can delegate vital sign monitoring to a CNA: 'Take vitals every 30 minutes. Report immediately if temperature rises more than 1 degree, if the patient develops any rash, itching, back pain, or difficulty breathing.'","Transfusion delegation scope limitation.","intermediate"),
  q("sq-bg15-17",ws,"patient_safety","A patient develops ventilator-associated pneumonia.","How would you help prevent VAP?","VAP prevention bundle includes: head of bed elevation 30-45 degrees, daily sedation vacation, daily spontaneous breathing trial assessment, oral care with chlorhexidine every 4 hours, peptic ulcer prophylaxis, DVT prophylaxis, and hand hygiene. Each element addresses a specific pathophysiology of VAP. Compliance with the entire bundle significantly reduces VAP rates.","VAP prevention bundle compliance.","beginner"),
  q("sq-bg15-18",ws,"medication_error","A pharmacy sends a medication in the wrong concentration.","How would you catch a wrong concentration dispensing error?","I would verify the concentration against the order before administration, check the medication label against the MAR, use the barcode scanner as verification, and question any discrepancy immediately. Concentration errors are particularly dangerous with high-alert medications like insulin and heparin where the wrong concentration can cause a 10-fold dosing error.","Concentration verification before administration.","intermediate"),
  q("sq-bg15-19",ws,"handoff_communication","You are giving report on a patient with multiple comorbidities.","How would you organize a complex comorbidity handoff?","I would organize by system rather than chronologically: 'Cardiac: AFib on amiodarone, INR therapeutic. Respiratory: COPD on 2L NC, baseline SpO2 92%. Renal: CKD stage 3, creatinine stable at 2.1. Endocrine: DM2, on sliding scale, blood sugars 140-200. Then: current concerns, pending items, and anticipated needs.'","System-based complex handoff organization.","intermediate"),
  q("sq-bg15-20",ws,"difficult_coworkers","A colleague gossips about patients in common areas.","How would you address patient privacy violations?","I would address it directly and privately: 'I noticed you were discussing Mrs. Smith's diagnosis in the break room. Even without using her name, the details could identify her. HIPAA violations can result in termination and fines. I know you care about patients—let us keep their information private.' If the behavior continues, I would report to the charge nurse.","HIPAA violation collegial correction.","beginner"),
  q("sq-bg15-21",ws,"interdisciplinary_communication","A specialist makes recommendations that conflict with the primary team's plan.","How would you navigate conflicting specialist recommendations?","I would document both recommendations clearly, communicate the discrepancy to the primary physician: 'Cardiology recommends continuing anticoagulation while GI recommends holding it for the procedure. Could you clarify which plan to follow?' I would not implement either conflicting order without clarification. Conflicting specialist recommendations are a common patient safety risk.","Conflicting specialist plan resolution.","intermediate"),
  q("sq-bg15-22",ct,"first_shift","You are learning to prioritize multiple patient alarms.","How would you triage multiple simultaneous alarms?","I would prioritize by clinical significance: cardiac arrest alarm first, then desaturation alarms, then tachycardia or bradycardia, then IV pump alarms, then bed alarms. I would silence non-critical alarms only after assessment, never disable alarms, and address alarm fatigue by ensuring alarm parameters are individualized to each patient's baseline.","Multiple alarm triage hierarchy.","beginner"),
  q("sq-bg15-23",ct,"new_nurse_anxiety","You feel like you are asking too many questions.","Is asking too many questions a problem for new nurses?","Asking questions is the hallmark of a safe new nurse. Experienced nurses worry about new nurses who never ask questions. I would ask questions without apology, frame them as learning opportunities, and thank colleagues for their patience. The only dangerous question is the one not asked. My questions will decrease naturally as my experience grows.","Question-asking as safety behavior.","beginner"),
  q("sq-bg15-24",ct,"time_management","You need to develop a system for tracking lab results.","How would you track multiple pending lab results?","I would maintain a tracking system on my brain sheet listing: patient, test ordered, time drawn, expected result time, and critical values that require immediate action. I would set reminders to check results at expected times, follow up on delayed results, and report critical values immediately. A missed critical lab result can delay life-saving treatment.","Lab result tracking system.","beginner"),
  q("sq-bg15-25",ct,"documentation_challenges","You need to document a restraint assessment.","What must restraint documentation include?","I would document: clinical justification with specific behavior, physician order with time limits, restraint type and location, circulation checks every 2 hours, skin assessment under restraints, offer of food/fluids/toileting, continued need assessment, patient's response, attempts at least restrictive alternatives, and release criteria. Restraint documentation is heavily regulated.","Restraint documentation regulatory requirements.","intermediate"),
  q("sq-bg15-26",ct,"critical_thinking_drills","A patient's ammonia level is 120.","What does elevated ammonia indicate?","Ammonia of 120 (normal 15-45) indicates hepatic encephalopathy from the liver's inability to convert ammonia to urea. I would assess neurological status, administer lactulose to promote ammonia excretion, restrict dietary protein if ordered, monitor for asterixis, and implement fall precautions. Ammonia levels correlate roughly with encephalopathy severity.","Ammonia elevation with lactulose treatment.","intermediate"),
  q("sq-bg15-27",pd,"professional_boundaries","A dying patient asks you to promise to attend their funeral.","How would you handle a funeral attendance request?","I would respond honestly: 'Being part of your care has been meaningful to me. I cannot make specific promises about attending, but I want you to know that the impact you have had on me as a nurse will stay with me. Right now, my focus is on making sure you are comfortable and your needs are met.'","Funeral attendance thoughtful response.","intermediate"),
  q("sq-bg15-28",pd,"ethical_dilemmas","You suspect a patient is a victim of human trafficking.","How would you assess for human trafficking?","Red flags include: patient accompanied by someone who answers all questions, inconsistent story, signs of physical abuse, lack of personal identification, fearful behavior, and working conditions inconsistent with patient's age. I would interview the patient alone if possible, use screening tools, and report to social work and law enforcement per facility protocol.","Human trafficking screening and reporting.","intermediate"),
  q("sq-bg15-29",pd,"advocacy","A non-English-speaking patient is receiving care without an interpreter.","How would you advocate for language-appropriate care?","I would immediately arrange professional interpreter services—federal law requires language access for patients. I would not use family members as interpreters for clinical discussions (accuracy and confidentiality concerns). I would document interpreter use, ensure patient education materials are provided in their language, and report language access barriers.","Language access legal advocacy.","intermediate"),
  q("sq-bg15-30",pd,"patient_communication","A patient's family is fighting about care decisions at the bedside.","How would you manage bedside family conflict?","I would separate the conflict from the patient: 'I can see you all care deeply about your loved one. However, this discussion is causing stress for the patient. Let us move to the family conference room where we can discuss this with the social worker and physician present to help answer questions and mediate.'","Family conflict patient-centered de-escalation.","intermediate"),
  q("sq-bg15-31",pd,"workplace_bullying","You are being excluded from educational opportunities.","How would you address exclusion from education?","I would document the pattern and address it directly: 'I noticed I was not included in the last three educational opportunities on the unit. I am committed to my professional development and want to ensure I have equal access to learning opportunities. Can we discuss how these opportunities are distributed?'","Educational exclusion documentation and advocacy.","intermediate"),
  q("sq-bg15-32",cn,"job_offer_negotiation","You received two job offers and need to decide.","How would you evaluate competing job offers?","I would create a comparison matrix: base salary, shift differentials, total benefits value, commute time, unit culture (assess during shadow day), orientation program quality, nurse-to-patient ratios, advancement opportunities, tuition benefits, and gut feeling about the team. The highest salary is not always the best offer—total value and fit matter more.","Job offer comparison matrix approach.","beginner"),
  q("sq-bg15-33",cn,"probation_period","You receive mixed feedback during probation.","How would you process mixed feedback?","I would focus on actionable items: categorize feedback into strengths to maintain and specific areas to improve. I would create an improvement plan with measurable goals for each concern, schedule follow-up discussions, and acknowledge progress. Mixed feedback is normal—no one is perfect during their first months. Demonstrate consistent improvement trajectory.","Mixed feedback actionable processing.","beginner"),
  q("sq-bg15-34",cn,"career_advancement","You want to understand nursing informatics certification.","How would you pursue informatics certification?","The ANCC offers nursing informatics board certification requiring: BSN, 2 years RN experience, 2000 hours in informatics, and 30 hours of informatics CE. Alternative paths include AHIMA health informatics certification. Informatics nurses bridge clinical practice and technology—designing EHR workflows, implementing decision support, and analyzing clinical data for quality improvement.","Nursing informatics certification pathway.","intermediate"),
  q("sq-bg15-35",cn,"performance_evaluation","You want to document clinical growth for evaluation.","How would you track clinical growth throughout the year?","I would maintain a professional portfolio with: skills mastered with dates, patient outcomes achieved, challenging scenarios managed successfully, positive feedback received, certifications obtained, education completed, committee participation, and specific examples of applying evidence-based practice. A portfolio provides concrete evidence rather than vague self-assessment.","Professional portfolio for evaluation evidence.","beginner"),
  q("sq-bg15-36",ip,"clinical_judgment","A patient develops hemolytic uremic syndrome.","What is HUS and how would you manage it?","HUS presents with microangiopathic hemolytic anemia, thrombocytopenia, and acute renal failure, typically following E. coli O157:H7 infection. Unlike TTP, HUS predominantly affects the kidneys. Treatment is supportive: fluid management, dialysis if needed, blood transfusions, and blood pressure control. Antibiotics may worsen HUS by increasing toxin release from killed bacteria.","HUS management with antibiotic caution.","advanced"),
  q("sq-bg15-37",ws,"patient_safety","A patient develops contrast extravasation during CT scan.","How would you manage contrast extravasation?","I would elevate the affected extremity, apply cold compresses for the first 24 hours, measure the area of swelling, assess neurovascular status distally, document the volume extravasated, and notify radiology. For large volume extravasation (>100mL) or concerning symptoms (increasing pain, decreased sensation, compartment-like symptoms), surgical consultation is warranted.","Contrast extravasation management.","beginner"),
  q("sq-bg15-38",ct,"critical_thinking_drills","A patient's thyroid panel shows low TSH with elevated T4.","What does this thyroid pattern indicate?","Low TSH with elevated T4 indicates hyperthyroidism—the thyroid is producing excess hormone, suppressing TSH through negative feedback. Causes include Graves' disease, toxic multinodular goiter, and thyroiditis. I would assess for symptoms: tachycardia, weight loss, tremor, heat intolerance, and anxiety. Treatment includes antithyroid medications, radioactive iodine, or surgery.","Hyperthyroidism lab interpretation.","beginner"),
  q("sq-bg15-39",pd,"ethical_dilemmas","A patient wants to leave their entire estate to the hospital in their will.","How would you handle a patient's bequest intentions?","I would not become involved in estate decisions: 'I appreciate your gratitude for your care. However, estate decisions should be made with your family and an attorney, not with healthcare providers who could be perceived as having undue influence. I can ask our social worker to help connect you with appropriate legal resources.'","Bequest undue influence avoidance.","intermediate"),
  q("sq-bg15-40",cn,"career_advancement","You want to understand the role of parish nursing.","What is parish or faith community nursing?","Parish nurses serve faith communities by integrating health and healing within the context of spiritual care. They provide health education, screenings, advocacy, counseling, and referrals. No formal certification is required but IPNRC courses are available. Parish nursing appeals to nurses who want to combine clinical knowledge with spiritual ministry in a community-based setting.","Parish nursing career overview.","beginner"),
  q("sq-bg15-41",ip,"clinical_judgment","A patient develops immune thrombocytopenic purpura.","How would you manage ITP?","ITP is autoimmune platelet destruction presenting with petechiae, purpura, and bleeding with severely low platelets. Treatment includes corticosteroids, IVIG for rapid platelet increase, and platelet transfusion only for life-threatening bleeding (transfused platelets are also destroyed). I would implement bleeding precautions, avoid IM injections and rectal temperatures, and use soft toothbrushes.","ITP with platelet transfusion limitation.","intermediate"),
  q("sq-bg15-42",ws,"delegation","You need to delegate monitoring a post-seizure patient.","How would you delegate post-ictal monitoring?","I would specify: 'Mr. Adams had a seizure at 1345. He is now post-ictal and confused. Stay with him, keep side rails up, position him on his side, do not restrain him, check vital signs every 15 minutes, and call me immediately if he has another seizure, develops respiratory difficulty, or does not return to baseline within 30 minutes.'","Post-ictal monitoring delegation.","beginner"),
  q("sq-bg15-43",ct,"documentation_challenges","You need to document a pain reassessment after medication administration.","How would you document pain reassessment?","I would document: 'Pain reassessment 30 minutes post-morphine 4mg IV. Pain decreased from 8/10 to 4/10. Patient reports the medication helped but pain is not adequately controlled. Location and quality unchanged—right hip, sharp with movement. Patient able to participate in PT at this level. Will reassess in 1 hour and consider additional intervention if pain increases.'","Pain reassessment with medication effectiveness evaluation.","beginner"),
  q("sq-bg15-44",pd,"patient_communication","A patient is refusing to participate in rehabilitation.","How would you motivate a reluctant rehabilitation patient?","I would explore the resistance: 'I notice you have been declining PT sessions. Can you help me understand what is holding you back? Is it pain, fatigue, discouragement, or something else?' Once I understand the barrier, I can address it specifically. I would celebrate small achievements and help the patient visualize their recovery goals in concrete terms.","Rehabilitation motivation through barrier identification.","beginner"),
  q("sq-bg15-45",cn,"career_advancement","You want to understand the growing field of nurse wellness.","What is the nurse wellness movement?","Nurse wellness recognizes that healthy nurses provide better care. Emerging roles include: wellness coordinator, resilience program director, peer support specialist, and employee health nurse with mental health focus. Organizations are investing in nurse wellness programs including yoga, meditation rooms, therapy access, and flexible scheduling to reduce burnout and retain staff.","Nurse wellness movement overview.","beginner"),
  q("sq-bg15-46",ip,"clinical_judgment","A patient on lithium develops toxicity.","How would you recognize lithium toxicity?","Lithium has a narrow therapeutic index (0.6-1.2 mEq/L). Toxicity presents progressively: mild (1.5-2.0)—tremor, nausea, diarrhea; moderate (2.0-2.5)—confusion, ataxia, fasciculations; severe (>2.5)—seizures, coma, cardiac arrhythmias. Treatment includes stopping lithium, aggressive hydration, and hemodialysis for severe cases. I would check renal function and sodium levels.","Lithium toxicity progressive recognition.","intermediate"),
  q("sq-bg15-47",ws,"patient_safety","A patient develops a catheter-associated urinary tract infection.","How would you help prevent CAUTI?","CAUTI prevention includes: avoiding unnecessary catheter insertion, daily assessment for catheter necessity, removing catheters as soon as possible, maintaining a closed drainage system, securing the catheter to prevent movement, keeping the bag below the bladder, performing perineal care, and using aseptic technique for insertion. Nurse-driven catheter removal protocols reduce CAUTI rates.","CAUTI prevention bundle.","beginner"),
  q("sq-bg15-48",ct,"critical_thinking_drills","A patient's calcium is 12.5 mg/dL.","How would you manage hypercalcemia?","Calcium of 12.5 (normal 8.5-10.5) can cause confusion, constipation, polyuria, nausea, and cardiac arrhythmias. Common causes are malignancy and hyperparathyroidism. I would administer aggressive IV normal saline for renal calcium excretion, loop diuretics after adequate hydration, and anticipate bisphosphonate or calcitonin administration. I would monitor cardiac rhythm continuously.","Hypercalcemia management with saline-first approach.","intermediate"),
  q("sq-bg15-49",pd,"advocacy","A patient needs palliative care but the family resists the referral.","How would you facilitate palliative care discussion?","I would clarify the misconception: 'Palliative care is not giving up—it is adding another layer of support focused on comfort and quality of life alongside the current treatment plan. Palliative care can be provided at any stage of illness. Would you be open to meeting the team to learn more about how they can help?' Education resolves most resistance.","Palliative care misconception correction.","intermediate"),
  q("sq-bg15-50",cn,"career_advancement","You want to understand global nursing opportunities.","What international nursing opportunities exist?","Options include: military nursing, WHO assignments, Doctors Without Borders (which employs nurses), travel nursing in countries with reciprocal agreements, academic nursing exchange programs, global health fellowships, and disaster response teams. Requirements vary: some need specialty experience, language skills, or additional certifications. Global nursing broadens perspective and builds adaptability.","Global nursing opportunity overview.","beginner"),
  q("sq-bg15-51",ip,"clinical_judgment","A patient develops hyponatremia with seizures.","How would you manage acute symptomatic hyponatremia?","Acute symptomatic hyponatremia (Na <120 with seizures or severe confusion) requires urgent treatment with 3% hypertonic saline 100mL IV over 10 minutes, repeatable up to 3 times for seizures. Correction must not exceed 8 mEq/L in 24 hours to prevent osmotic demyelination syndrome. I would check sodium every 2 hours and monitor neurological status closely.","Hyponatremia emergency with correction limits.","advanced"),
  q("sq-bg15-52",ws,"medication_error","You realize you documented a medication as given but it was not administered.","How would you correct a documentation error?","I would immediately correct the documentation using a late entry or addendum: 'Late entry: medication [name, dose] documented as given at [time] was not administered due to [reason]. Correcting the record to reflect that this dose was not given.' I would then assess whether the missed dose requires administration and notify the physician. I would file a medication error report.","Documentation error correction with transparency.","beginner"),
  q("sq-bg15-53",ct,"first_shift","You encounter your first patient death.","How would you process your first patient death?","I would allow myself to feel the emotions—grief, sadness, or even relief if the patient was suffering. I would perform post-mortem care with dignity and respect, support the family's grief, and seek debriefing from my charge nurse or preceptor afterward. The first patient death is a formative nursing experience. Seeking peer support is not weakness—it is professional self-care.","First patient death emotional processing.","beginner"),
  q("sq-bg15-54",pd,"ethical_dilemmas","A physician asks you to falsify documentation.","How would you refuse a documentation falsification request?","I would refuse clearly: 'I cannot document something that did not occur. Falsified documentation puts the patient at risk, violates my nursing license, and exposes both of us to legal liability. I need to document what actually happened.' If the physician persists, I would report to my charge nurse, nursing supervisor, and follow the chain of command.","Documentation falsification refusal with chain of command.","intermediate"),
  q("sq-bg15-55",cn,"career_advancement","You want to understand nurse entrepreneurship.","What business opportunities exist for nurse entrepreneurs?","Nurse entrepreneurs can start: legal nurse consulting firms, health coaching practices, nurse staffing agencies, continuing education companies, healthcare product companies, wellness programs, telehealth services, and expert witness practices. Success requires: business knowledge, clinical credibility, marketing skills, and understanding of healthcare regulations. Many nurses start side businesses while employed.","Nurse entrepreneurship landscape.","beginner"),
  q("sq-bg15-56",ip,"clinical_judgment","A patient develops autonomic dysreflexia.","How would you manage autonomic dysreflexia?","Autonomic dysreflexia occurs in spinal cord injuries at T6 or above, triggered by noxious stimuli below the injury (distended bladder, fecal impaction, skin irritation). It presents with severe hypertension, pounding headache, flushing and sweating above the injury, and bradycardia. I would sit the patient upright, loosen tight clothing, identify and remove the trigger (catheterize, disimpact), and treat hypertension if needed.","Autonomic dysreflexia trigger removal priority.","advanced"),
  q("sq-bg15-57",ws,"handoff_communication","A patient has been receiving conflicting information from different providers.","How would you address conflicting information in handoff?","I would document and communicate: 'The patient received conflicting information—cardiology recommended anticoagulation while surgery recommended holding it. I clarified with the attending who confirmed we should hold anticoagulation for now. The patient is aware of the resolution. Please reinforce consistent messaging with the patient to rebuild their confidence in the care plan.'","Conflicting information resolution handoff.","intermediate"),
  q("sq-bg15-58",ct,"critical_thinking_drills","A patient's ABG shows pH 7.28, PCO2 55, HCO3 26.","How would you interpret this ABG?","pH 7.28 is acidotic, PCO2 55 is elevated (respiratory acidosis), and HCO3 26 is slightly elevated (beginning renal compensation). This is acute respiratory acidosis with early compensation—the kidneys have not had time to fully compensate. I would assess respiratory function, check for airway obstruction or hypoventilation causes, and prepare for possible ventilatory support.","Acute respiratory acidosis with early compensation.","intermediate"),
  q("sq-bg15-59",pd,"patient_communication","A patient is refusing a blood transfusion due to religious beliefs.","How would you support a patient refusing transfusion for religious reasons?","I would respect their autonomy: 'I understand and respect your beliefs. I want to make sure you understand the potential consequences, and I will work with your medical team to explore all alternative treatments. We have bloodless medicine options including iron supplementation, erythropoietin, and careful surgical techniques to minimize blood loss.'","Religious transfusion refusal with alternatives.","intermediate"),
  q("sq-bg15-60",cn,"career_advancement","You want to understand the role of flight nursing.","What does flight nursing involve?","Flight nurses provide critical care in helicopter and fixed-wing aircraft environments, managing trauma, cardiac emergencies, and critical transfers. Requirements include: 3-5 years ICU or ED experience, CCRN and CEN certifications, flight physiology knowledge, ACLS/PALS/NRP, and physical fitness. The role demands autonomous decision-making in austere environments with limited resources and team size.","Flight nursing career requirements.","intermediate"),
  q("sq-bg15-61",ip,"clinical_judgment","A patient develops pheochromocytoma crisis.","How would you manage a pheochromocytoma crisis?","Pheochromocytoma causes catecholamine surges producing severe paroxysmal hypertension, headache, diaphoresis, and palpitations. Management requires alpha-blockade first (phentolamine or phenoxybenzamine), then beta-blockade only after adequate alpha-blockade is established. Beta-blockers alone are contraindicated—they worsen hypertension by blocking vasodilatory beta-2 receptors, leaving alpha vasoconstriction unopposed.","Pheo crisis alpha-before-beta rule.","advanced"),
  q("sq-bg15-62",ws,"patient_safety","A patient develops central line-associated bloodstream infection.","How would you help prevent CLABSI?","CLABSI prevention bundle: hand hygiene, maximal sterile barriers during insertion, chlorhexidine skin prep, optimal catheter site selection (avoid femoral in adults), daily assessment of line necessity, scrub the hub for 15 seconds before access, dressing changes per protocol, and daily chlorhexidine bathing for ICU patients.","CLABSI prevention bundle elements.","beginner"),
  q("sq-bg15-63",ct,"time_management","You need to efficiently manage admission paperwork.","How would you streamline the admission process?","I would develop a systematic approach: perform initial safety assessment first (fall risk, skin, airway), then vital signs and focused assessment, then complete the admission history using the EHR template efficiently, then place admission orders. I would cluster initial education with assessment and defer non-urgent education to subsequent shifts.","Admission process efficiency optimization.","beginner"),
  q("sq-bg15-64",pd,"workplace_bullying","A preceptor is overly critical and never offers positive feedback.","How would you address an overly critical preceptor?","I would request a private conversation: 'I value your teaching and want to improve. I notice your feedback focuses on what I need to fix. Could you also let me know what I am doing well so I can reinforce those behaviors? Understanding both my strengths and weaknesses helps me develop more effectively.'","Balanced feedback request from preceptor.","beginner"),
  q("sq-bg15-65",cn,"probation_period","You want to build a relationship with your unit educator.","How would you leverage the unit educator relationship?","I would attend all education sessions, ask thoughtful questions, volunteer for skills validation, express interest in additional learning opportunities, share relevant articles or resources, and communicate my learning goals. The unit educator is an advocate for my development and can open doors to certifications, conferences, and specialty training.","Unit educator relationship investment.","beginner"),
  q("sq-bg15-66",ip,"clinical_judgment","A patient develops myxedema coma.","How would you manage myxedema coma?","Myxedema coma is a life-threatening severe hypothyroidism emergency presenting with hypothermia, bradycardia, hypotension, altered consciousness, and respiratory depression. Treatment includes IV levothyroxine loading dose, IV hydrocortisone (to prevent adrenal crisis from increased metabolism), passive rewarming (active warming can cause vasodilation and cardiovascular collapse), and ventilatory support.","Myxedema coma with passive warming.","advanced"),
  q("sq-bg15-67",ws,"delegation","You need to delegate range-of-motion exercises.","How would you delegate ROM exercises?","I would specify: 'Please assist Mrs. Chen with passive range-of-motion exercises for all joints as demonstrated by physical therapy. Move each joint through the full range 5 times, gently. Stop immediately if she reports pain or if you feel resistance. Do not force any movement. Document completion and any limitations noted. She should be medicated for pain 30 minutes before we start.'","ROM exercise delegation with pain precautions.","beginner"),
  q("sq-bg15-68",ct,"documentation_challenges","You need to document a blood transfusion reaction.","What must transfusion reaction documentation include?","I would document: time reaction recognized, symptoms (fever, chills, urticaria, dyspnea, hypotension), transfusion stopped at [time], blood bank and physician notified at [time], blood product and tubing returned to lab, vitals at time of reaction and every 15 minutes after, interventions given, patient response, and post-reaction urine sample sent.","Transfusion reaction comprehensive documentation.","intermediate"),
  q("sq-bg15-69",pd,"advocacy","A patient needs a mobility device but insurance will not cover it.","How would you help obtain a mobility device?","I would explore alternatives: appeal the insurance denial with detailed medical necessity documentation, check charitable organizations that provide mobility equipment, investigate refurbished equipment programs, connect with physical therapy for adaptive equipment recommendations, and explore community resources and Lions Club or Rotary assistance programs.","Mobility device access creative advocacy.","beginner"),
  q("sq-bg15-70",cn,"career_advancement","You want to understand the role of nursing in policy advocacy.","How can nurses influence healthcare policy?","Nurses can influence policy through: joining professional organizations that lobby, testifying at legislative hearings, serving on advisory committees, running for public office, writing letters to legislators, participating in grassroots campaigns, voting informed by healthcare issues, and using social media for advocacy. Nurses are consistently rated the most trusted profession—our voice carries weight.","Nursing policy advocacy pathways.","beginner"),
  q("sq-bg15-71",ip,"clinical_judgment","A patient develops thyroid storm.","How would you manage thyroid storm?","Thyroid storm is life-threatening thyrotoxicosis with high fever (>104°F), severe tachycardia, delirium, and cardiovascular collapse. Treatment order matters: propylthiouracil or methimazole first (blocks new hormone synthesis), then iodine solution one hour later (blocks hormone release—must wait for synthesis blockade), beta-blockers for rate control, hydrocortisone for relative adrenal insufficiency, and aggressive cooling.","Thyroid storm treatment order.","advanced"),
  q("sq-bg15-72",ws,"patient_safety","A patient develops opioid-induced respiratory depression.","How would you manage opioid-induced respiratory depression?","I would stimulate the patient, open the airway, provide bag-mask ventilation, and administer naloxone 0.04-0.4mg IV titrated to respiratory rate—not to pain reversal. Full reversal with high-dose naloxone causes severe pain, hypertension, and potential pulmonary edema. I would monitor for re-sedation as naloxone's duration is shorter than most opioids.","Opioid respiratory depression with naloxone titration.","intermediate"),
  q("sq-bg15-73",ct,"critical_thinking_drills","A patient's lactate dehydrogenase is elevated with low haptoglobin.","What do elevated LDH with low haptoglobin indicate?","This combination strongly suggests hemolysis—red blood cell destruction. Haptoglobin binds free hemoglobin and decreases during hemolysis; LDH releases from lysed cells. I would check for schistocytes on peripheral smear, check indirect bilirubin, and assess for hemolytic causes: autoimmune, mechanical (prosthetic valve), DIC, TTP/HUS, or transfusion reaction.","Hemolysis lab pattern recognition.","intermediate"),
  q("sq-bg15-74",pd,"ethical_dilemmas","A colleague asks you to sign off on competencies they have not completed.","How would you handle a false competency request?","I would decline: 'I cannot sign off on competencies that were not completed under my observation. This protects both of us and our patients. Let me help you schedule a time to complete these competencies properly.' Falsifying competency records puts patients at risk and could result in termination and license action for both parties.","Competency falsification refusal.","beginner"),
  q("sq-bg15-75",cn,"career_advancement","You want to understand the role of nurse anesthetists.","What does a CRNA do?","CRNAs are advanced practice nurses who administer anesthesia independently or collaboratively with anesthesiologists. They provide the majority of anesthesia in rural settings. Requirements include: BSN, 1-2 years ICU experience, doctoral program (DNAP/DNP) completion, and national certification. CRNAs are among the highest-paid nursing specialties with excellent autonomy and job satisfaction.","CRNA career overview and requirements.","intermediate"),
  q("sq-bg15-76",ip,"clinical_judgment","A patient develops hepatorenal syndrome.","What is hepatorenal syndrome?","Hepatorenal syndrome is functional renal failure in severe liver disease caused by intense renal vasoconstriction despite normal kidney histology. Type 1 progresses rapidly with doubling of creatinine in 2 weeks; Type 2 progresses slowly. Treatment includes albumin, vasopressors (terlipressin or norepinephrine plus albumin), and ultimately liver transplantation as the definitive cure.","Hepatorenal syndrome functional renal failure.","advanced"),
  q("sq-bg15-77",ws,"interdisciplinary_communication","A rapid response is called and multiple disciplines arrive simultaneously.","How would you communicate effectively during a rapid response?","I would use closed-loop communication: state patient's name, situation, and what I have done; use clear role assignments; repeat orders back; and designate one person for documentation. I would provide a concise SBAR to the responding physician and ensure all team members know the patient's code status and relevant history.","Rapid response team communication.","intermediate"),
  q("sq-bg15-78",ct,"new_nurse_anxiety","You made a minor error and cannot stop thinking about it.","How would you process making a clinical error?","I would acknowledge the error, report it properly, analyze what went wrong, identify system and personal factors, develop prevention strategies, and forgive myself. Every nurse makes errors—the measure of a nurse is not perfection but how they respond to mistakes. I would seek debriefing and use the experience as a learning tool rather than a source of shame.","Error processing with self-forgiveness.","beginner"),
  q("sq-bg15-79",pd,"patient_communication","A patient is non-compliant with their care plan.","How would you address non-adherence without judgment?","I would explore barriers: 'I notice you have not been taking your blood pressure medication regularly. Can you help me understand what is making it difficult? Is it the cost, the side effects, forgetting, or something else?' Understanding barriers allows me to help solve problems rather than lecture. I would use non-adherence rather than non-compliance—language matters.","Non-adherence barrier exploration versus lecturing.","beginner"),
  q("sq-bg15-80",cn,"performance_evaluation","You want to establish yourself as a resource nurse.","How would you demonstrate resource nurse readiness?","I would demonstrate: consistent clinical excellence, willingness to help colleagues, knowledge sharing, calm demeanor during emergencies, problem-solving initiative, and positive feedback from patients and peers. I would express my interest: 'I would like to develop into a resource role. What additional skills or experiences do I need to prepare for this?'","Resource nurse readiness demonstration.","beginner"),
  q("sq-bg15-81",ip,"clinical_judgment","A patient develops HELLP syndrome.","What is HELLP syndrome?","HELLP is a severe pregnancy complication: Hemolysis, Elevated Liver enzymes, Low Platelets. It can occur with or without preeclampsia and presents with epigastric pain, nausea, malaise, and potentially liver rupture. The definitive treatment is delivery. I would monitor for DIC, ensure blood products are available, and support immediate obstetric management.","HELLP syndrome emergency delivery indication.","advanced"),
  q("sq-bg15-82",ws,"medication_error","A patient's medication allergy band is missing.","How would you address a missing allergy band?","I would verify allergies from multiple sources: MAR, chart, and patient confirmation. I would immediately replace the allergy band with correct information, update the EHR if needed, and file a safety report about the missing band. Missing allergy identification is a system failure that can lead to life-threatening medication errors.","Missing allergy band multi-source verification.","beginner"),
  q("sq-bg15-83",ct,"documentation_challenges","You need to document patient goals of care.","How would you document a goals of care discussion?","I would document: participants present, patient's stated values and priorities, specific treatment preferences discussed (resuscitation, ventilation, dialysis, artificial nutrition), patient's understanding of their prognosis as verified by teach-back, decisions made, any areas of disagreement noted, plan for follow-up discussion if decisions were deferred, and code status updated accordingly.","Goals of care discussion documentation.","intermediate"),
  q("sq-bg15-84",pd,"professional_boundaries","A patient gives you a handwritten thank-you letter.","How would you receive a patient's thank-you letter?","I would accept it graciously: 'Thank you—this means a great deal to me. Your words remind me why I became a nurse.' A handwritten letter is a heartfelt expression of gratitude that is appropriate to accept. I might share it with my manager as positive feedback. Letters of appreciation are different from gifts of monetary value and are professionally acceptable.","Thank-you letter gracious acceptance.","beginner"),
  q("sq-bg15-85",cn,"career_advancement","You want to understand the role of school nursing.","What does a school nurse do?","School nurses provide: health assessments and screenings, chronic disease management (diabetes, asthma, epilepsy), emergency care, health education, immunization compliance tracking, mental health support, IEP and 504 plan health components, and health policy development. School nursing requires independent judgment, as you are often the sole healthcare professional in the building.","School nursing comprehensive role.","beginner"),
  q("sq-bg15-86",ip,"clinical_judgment","A patient on warfarin needs urgent surgery.","How would you reverse warfarin for urgent surgery?","For urgent surgery, warfarin is reversed with IV vitamin K (onset 6-12 hours) plus either fresh frozen plasma or 4-factor prothrombin complex concentrate (PCC) for immediate reversal. PCC is preferred over FFP: it acts within minutes, requires less volume, and carries lower transfusion reaction risk. I would recheck INR 30 minutes after PCC administration.","Warfarin urgent reversal with PCC preference.","advanced"),
  q("sq-bg15-87",ws,"patient_safety","A patient develops hypoglycemia unawareness.","How would you manage a patient with hypoglycemia unawareness?","Hypoglycemia unawareness means the patient does not recognize low blood sugar symptoms until dangerously low levels. I would maintain higher glucose targets (140-180 rather than 80-130), increase monitoring frequency, educate about continuous glucose monitoring options, avoid insulin dose increases, and ensure the patient and family can recognize subtle hypoglycemia signs and treat promptly.","Hypoglycemia unawareness adapted management.","intermediate"),
  q("sq-bg15-88",ct,"critical_thinking_drills","A patient's BUN-to-creatinine ratio is 35:1.","What does a high BUN-to-creatinine ratio indicate?","BUN:Cr ratio >20:1 suggests prerenal azotemia (dehydration, decreased cardiac output, bleeding) where the kidneys are underperfused but structurally intact. Intrinsic renal disease typically shows BUN:Cr ratio of 10-15:1. A high ratio can also indicate GI bleeding (digested blood increases BUN) or high protein intake. I would assess hydration status and check for GI bleeding.","BUN-Cr ratio prerenal versus intrinsic differentiation.","intermediate"),
  q("sq-bg15-89",pd,"advocacy","A patient needs home modifications for safe discharge but cannot afford them.","How would you advocate for home modification resources?","I would involve OT for a home assessment, connect with social work for community resources, research grants for home modifications (Rebuilding Together, Habitat for Humanity aging-in-place programs), check Veterans Affairs benefits if applicable, explore Medicaid waiver programs, and coordinate with community organizations that provide ramps, grab bars, and accessibility modifications.","Home modification resource advocacy.","beginner"),
  q("sq-bg15-90",cn,"career_advancement","You want to understand correctional nursing.","What does correctional nursing involve?","Correctional nurses provide healthcare in jails, prisons, and detention facilities. The role includes: intake health screenings, chronic disease management, mental health assessment, medication administration, emergency response, and substance withdrawal management. It requires strong assessment skills, professional boundaries, non-judgmental attitude, and autonomous practice.","Correctional nursing overview.","beginner"),
  q("sq-bg15-91",ip,"clinical_judgment","A patient develops paradoxical reaction to benzodiazepines.","What is a paradoxical benzodiazepine reaction?","Instead of sedation, the patient becomes agitated, aggressive, or disinhibited. This occurs in approximately 1-2% of patients and is more common in elderly, pediatric, and psychiatric patients. I would stop the benzodiazepine, ensure patient and staff safety, document the paradoxical reaction, administer flumazenil if severe, and consider alternative sedation approaches.","Paradoxical benzodiazepine reaction management.","intermediate"),
  q("sq-bg15-92",ws,"handoff_communication","A patient has complex social issues affecting their care.","How would you include social determinants in handoff?","I would communicate: 'Social context: patient is uninsured, lives alone, has limited transportation, and food insecurity is impacting medication adherence—he skips meals to afford medications. Social work is involved. Case manager is arranging Medicaid application and medication assistance programs. Please continue to assess for nutritional status and medication compliance barriers.'","Social determinants handoff integration.","intermediate"),
  q("sq-bg15-93",ct,"time_management","You need to manage a patient who demands constant attention.","How would you manage a high-demand patient's expectations?","I would establish a proactive schedule: 'I will check on you every hour at the top of the hour. Between checks, please use your call light for urgent needs. I want to make sure you get the attention you need while I also care for my other patients safely.' Proactive rounding reduces call light use and builds patient trust.","High-demand patient proactive scheduling.","beginner"),
  q("sq-bg15-94",pd,"ethical_dilemmas","You discover a billing irregularity in patient charges.","How would you handle a billing concern?","I would document the discrepancy, report it to my supervisor and the compliance department, and avoid making accusations. Healthcare billing fraud is a federal offense. I would not ignore it, investigate independently, or discuss it outside proper channels. Whistleblower protections exist for healthcare workers who report billing concerns in good faith.","Billing irregularity proper reporting channels.","intermediate"),
  q("sq-bg15-95",cn,"career_advancement","You want to understand occupational health nursing.","What does occupational health nursing involve?","Occupational health nurses promote employee wellness, manage work-related injuries, conduct health screenings, implement safety programs, manage workers' compensation cases, and ensure OSHA compliance. Certification (COHN) is available. The role combines clinical skills with knowledge of occupational hazards, ergonomics, and workplace regulations. It offers primarily daytime scheduling.","Occupational health nursing career overview.","beginner"),
  q("sq-bg15-96",ip,"clinical_judgment","A patient develops peritonsillar abscess.","How would you manage a peritonsillar abscess?","Peritonsillar abscess presents with severe sore throat, trismus, muffled voice, uvular deviation, and drooling. It can obstruct the airway. I would maintain airway readiness, administer IV antibiotics, provide pain management, and prepare for incision and drainage or needle aspiration by ENT. This is urgent—delayed treatment can lead to parapharyngeal space infection and airway compromise.","Peritonsillar abscess airway emergency.","intermediate"),
  q("sq-bg15-97",ws,"patient_safety","A patient develops a pressure injury on a medical device.","How would you prevent medical device-related pressure injuries?","I would assess skin under and around all medical devices every shift: NG tubes, oxygen masks, ETT ties, cervical collars, SpO2 probes, and orthopedic devices. Prevention includes: proper sizing, regular repositioning of devices, padding between devices and skin, and ensuring devices are not overtightened. Medical device pressure injuries are increasingly recognized and preventable.","Medical device pressure injury prevention.","beginner"),
  q("sq-bg15-98",ct,"critical_thinking_drills","A patient's eosinophil count is markedly elevated.","What does eosinophilia indicate?","Marked eosinophilia indicates: allergic reactions, parasitic infections, drug reactions (especially DRESS syndrome), autoimmune conditions, or eosinophilic disorders. I would review recent medication changes, ask about travel history and parasite exposure, check for rash or other allergic symptoms, and correlate with the clinical presentation to identify the most likely cause.","Eosinophilia differential diagnosis approach.","intermediate"),
  q("sq-bg15-99",pd,"patient_communication","A patient is frustrated with the healthcare system.","How would you validate healthcare system frustration?","I would listen and acknowledge: 'Your frustration is understandable. Healthcare can be confusing, expensive, and sometimes feels impersonal. While I cannot fix the system, I can make sure your experience with me is different. What matters most to you right now? Let me focus on making this interaction as helpful as possible.'","System frustration validation with actionable care.","beginner"),
  q("sq-bg15-100",cn,"career_advancement","You want to create a 5-year nursing career plan.","How would you create a strategic career plan?","Year 1: establish clinical competence and pass any certification exams. Year 2: obtain specialty certification and begin committee involvement. Year 3: pursue charge nurse or preceptor role and start graduate school exploration. Year 4: begin advanced degree if desired and develop a specialty expertise area. Year 5: position for advanced practice, leadership, or specialized clinical role. Review and adjust annually.","Strategic 5-year career planning.","beginner"),
  q("sq-bg15-101",ip,"clinical_judgment","A patient develops central pontine myelinolysis.","What causes central pontine myelinolysis?","CPM results from overly rapid sodium correction in chronic hyponatremia, causing osmotic demyelination of the pons. It presents 2-6 days after correction with dysarthria, dysphagia, quadriparesis, and locked-in syndrome. Prevention requires limiting sodium correction to 8 mEq/L per 24 hours. There is no specific treatment—only supportive care. This is why I monitor sodium closely during correction.","CPM from rapid sodium correction.","advanced"),
  q("sq-bg15-102",ws,"difficult_coworkers","A senior nurse dismisses evidence-based practice changes.","How would you navigate resistance to EBP from senior staff?","I would approach respectfully: 'I have great respect for your experience. I found this recent evidence about [topic] and wondered what your thoughts are. Your clinical perspective combined with this research could help us develop the best approach for our patients.' Framing EBP as complementary to experience, not replacing it, reduces resistance.","EBP change resistance respectful navigation.","intermediate"),
  q("sq-bg15-103",ct,"first_shift","You are learning to manage a patient with multiple drains.","How would you organize care for a patient with multiple drains?","I would create a drain assessment chart: label each drain clearly, document drain type, insertion site, output color, consistency, and volume every shift, note any changes from previous assessments, ensure proper suction or gravity drainage settings, secure drains to prevent accidental dislodgement, and communicate drain management during handoff.","Multiple drain systematic management.","beginner"),
  q("sq-bg15-104",pd,"advocacy","A patient with disabilities faces access barriers in the hospital.","How would you advocate for disability access?","I would identify specific barriers, arrange appropriate assistive devices, ensure communication is accessible (large print, Braille, ASL interpreter), modify care delivery as needed, involve patient services for environmental modifications, and report systemic access barriers to administration. ADA compliance is both a legal requirement and a patient rights issue.","Disability access advocacy.","beginner"),
  q("sq-bg15-105",cn,"career_advancement","You want to understand the role of nurse midwives.","What does a certified nurse-midwife do?","CNMs are advanced practice nurses who provide comprehensive care across the lifespan of women: prenatal care, labor and delivery management, postpartum care, gynecological services, family planning, and primary care. Requirements include: MSN or DNP, national certification, and collaborative practice agreements in some states. CNMs attend approximately 12% of all US births.","CNM comprehensive role overview.","beginner"),
  q("sq-bg15-106",ip,"clinical_judgment","A patient develops cardiac tamponade.","How would you recognize cardiac tamponade?","Cardiac tamponade presents with Beck's triad: hypotension, muffled heart sounds, and jugular venous distension. Additional signs include pulsus paradoxus (>10mmHg drop in systolic BP during inspiration) and electrical alternans on ECG. This is a cardiac emergency requiring emergent pericardiocentesis. I would not delay for imaging if clinical suspicion is high and the patient is hemodynamically unstable.","Cardiac tamponade Beck's triad recognition.","advanced"),
  q("sq-bg15-107",ws,"patient_safety","A patient receiving chemotherapy develops febrile neutropenia.","How would you manage febrile neutropenia?","Febrile neutropenia (ANC <500 with fever >100.4°F) is an oncologic emergency. I would obtain blood cultures from all lumens, start broad-spectrum antibiotics within 1 hour of fever recognition, avoid rectal temperatures and IM injections, implement neutropenic precautions, and monitor for sepsis progression. Delayed antibiotics significantly increase mortality in febrile neutropenia.","Febrile neutropenia 1-hour antibiotic goal.","intermediate"),
  q("sq-bg15-108",ct,"critical_thinking_drills","A patient's troponin-I is 0.15 ng/mL.","How would you interpret a mildly elevated troponin?","Troponin I of 0.15 (normal <0.04) indicates myocardial injury. While acute MI is the primary concern, troponin elevation also occurs in: heart failure, PE, myocarditis, sepsis, renal failure, and tachyarrhythmias. Serial troponin measurements showing a rising pattern (delta troponin) suggest acute MI, while stable mild elevation suggests chronic injury from another cause.","Troponin interpretation with delta pattern importance.","intermediate"),
  q("sq-bg15-109",pd,"ethical_dilemmas","A patient wants to use an unproven alternative cancer treatment.","How would you respond to unproven cancer treatment interest?","I would listen without judgment: 'I understand you want every possible option. Let us discuss what we know about this treatment: what evidence exists, potential interactions with your current therapy, and risks. I want to support your autonomy while ensuring you have accurate information. Your oncologist can provide the most specific guidance about how this might interact with your treatment plan.'","Unproven treatment balanced information approach.","intermediate"),
  q("sq-bg15-110",cn,"career_advancement","You want to understand the growing role of mental health nursing.","Why is psychiatric nursing in high demand?","Mental health nursing demand is growing due to: the mental health crisis amplified by the pandemic, parity legislation expanding coverage, opioid epidemic treatment needs, integrated behavioral health in primary care, and telehealth expanding access. PMHNP is the fastest-growing NP specialty. Psychiatric nurses work across settings: inpatient, outpatient, community, forensic, and private practice.","Psychiatric nursing demand drivers.","beginner"),
  q("sq-bg15-111",ip,"clinical_judgment","A patient develops air trapping on the ventilator.","How would you recognize and manage auto-PEEP?","Auto-PEEP (air trapping) occurs when expiration is incomplete before the next breath, creating intrinsic positive end-expiratory pressure. Signs include: rising peak pressures, hemodynamic compromise from decreased venous return, and visible incomplete exhalation on the flow-time waveform. Management: increase expiratory time by reducing respiratory rate, decreasing I:E ratio, or disconnecting briefly to allow full exhalation.","Auto-PEEP recognition and management.","advanced"),
  q("sq-bg15-112",ws,"handoff_communication","You are doing bedside handoff and the patient disagrees with information.","How would you handle patient disagreement during bedside handoff?","I would address it immediately: 'Thank you for correcting that. Having you participate in handoff helps us ensure accuracy. Can you tell us more about what you experienced?' I would update the information, document the correction, and thank the patient for their active participation. Bedside handoff empowers patients to be safety partners.","Bedside handoff patient correction acknowledgment.","beginner"),
  q("sq-bg15-113",ct,"new_nurse_anxiety","You are afraid of making a critical error.","How would you manage fear of making fatal mistakes?","I would recognize that this fear is protective—it keeps me vigilant. But paralyzing fear is counterproductive. I would follow safety systems (scanning, double checks, verification), work within my scope, ask questions, and remember that modern healthcare has multiple safety layers to catch errors before they reach patients. Reasonable caution is healthy; debilitating fear needs professional support.","Critical error fear as protective versus paralyzing.","beginner"),
  q("sq-bg15-114",pd,"patient_communication","A dying patient wants to talk about their legacy.","How would you support a patient discussing their legacy?","I would be fully present: 'I would love to hear about what matters most to you and what you want people to remember.' I would listen without redirecting to medical topics, help them document wishes if desired, facilitate family conversations about legacy, and connect with social work for legacy-building activities like memory books or video messages.","Legacy conversation active listening support.","intermediate"),
  q("sq-bg15-115",cn,"performance_evaluation","You want to be recognized for mentorship contributions.","How would you document mentorship impact?","I would track: number of orientees and students mentored, their successful completion of orientation, specific skills I taught, feedback from mentees, and outcome improvements attributable to my mentorship. I would present: 'I mentored 3 new graduates this year. All completed orientation successfully and are now functioning independently. Two cited my mentorship as critical to their successful transition.'","Mentorship impact quantification.","beginner"),
  q("sq-bg15-116",ip,"clinical_judgment","A patient develops cerebral salt wasting versus SIADH.","How would you differentiate CSW from SIADH?","Both cause hyponatremia, but CSW involves volume depletion (dehydration) while SIADH involves euvolemia or mild hypervolemia. CSW shows high urine output with high urine sodium from renal salt wasting. Treatment differs: CSW requires aggressive saline replacement, while SIADH requires fluid restriction. Volume status assessment is the key differentiator.","CSW versus SIADH volume status differentiation.","advanced"),
  q("sq-bg15-117",ws,"patient_safety","A patient is at risk for aspiration during tube feeding.","How would you prevent aspiration during enteral feeding?","I would elevate the head of bed 30-45 degrees during and 1 hour after feeding, check gastric residual volumes per protocol, hold feeding if residuals exceed threshold, verify tube placement, use continuous rather than bolus feeds for high-risk patients, provide oral care, and monitor for aspiration signs (coughing, rhonchi, increased secretions, fever).","Enteral feeding aspiration prevention bundle.","beginner"),
  q("sq-bg15-118",ct,"documentation_challenges","You need to document an interdisciplinary care conference.","What should care conference documentation include?","I would document: date, time, participants and disciplines, patient's goals and preferences expressed, clinical status summary, treatment plan discussed, changes to the care plan agreed upon, family questions and responses, decisions made regarding discharge planning, follow-up actions assigned with responsible parties and timelines, and patient/family understanding verified.","Care conference documentation essentials.","beginner"),
  q("sq-bg15-119",pd,"professional_boundaries","You feel emotionally drained from caring for a dying patient.","How would you process grief while maintaining professional care?","I would acknowledge my grief as a sign of compassion, not weakness. I would continue providing excellent care while allowing myself to feel. After the shift, I would debrief with a trusted colleague, practice self-care, and consider attending a remembrance ceremony if offered. Sustainable nursing requires processing grief regularly rather than accumulating it.","Professional grief processing.","intermediate"),
  q("sq-bg15-120",cn,"career_advancement","You want to understand the future of nursing education.","How is nursing education evolving?","Trends include: simulation replacing some clinical hours, virtual reality for skill training, competency-based progression, interprofessional education emphasis, BSN as minimum entry standard moving forward, clinical residency programs for new graduates, lifelong learning requirements, and technology integration throughout curricula. Nursing education is becoming more experiential, technology-driven, and outcome-focused.","Nursing education evolution trends.","beginner"),
  q("sq-bg15-121",ip,"clinical_judgment","A patient develops abruptio placentae.","How would you recognize placental abruption?","Placental abruption presents with painful vaginal bleeding (usually dark), rigid tender uterus, and fetal distress. Concealed abruption may have no visible bleeding despite hemodynamic instability. This is an obstetric emergency requiring immediate delivery if the fetus is viable and the abruption is significant. I would establish large-bore IV access, type and crossmatch, and prepare for emergent cesarean.","Placental abruption with concealed hemorrhage.","advanced"),
  q("sq-bg15-122",ws,"delegation","You need to delegate care for a patient in isolation.","How would you delegate care for an isolated patient?","I would specify: 'Mr. Park is on airborne precautions for suspected TB. You must wear an N95 respirator—have you been fit-tested? A surgical mask is not sufficient. Put on the mask before entering, keep the door closed, and remove the mask only after exiting and closing the door. Bundle your care to minimize entries. Let me know if you need fit-testing.'","Isolation care delegation with PPE verification.","beginner"),
  q("sq-bg15-123",ct,"critical_thinking_drills","A patient's mixed venous oxygen saturation is 55%.","What does a low SvO2 indicate?","SvO2 of 55% (normal 60-80%) indicates that tissues are extracting more oxygen than normal, suggesting either inadequate oxygen delivery (low cardiac output, anemia, hypoxemia) or increased oxygen consumption (fever, pain, shivering). SvO2 below 60% suggests tissue hypoxia. I would assess cardiac output, hemoglobin, and oxygen delivery factors.","SvO2 as tissue oxygenation adequacy marker.","advanced"),
  q("sq-bg15-124",pd,"advocacy","A patient is being transferred to a facility of lower quality.","How would you advocate for appropriate transfer facility?","I would assess the receiving facility's capability for the patient's needs, communicate concerns to case management: 'This patient requires wound vac management and IV antibiotics. Does the receiving facility have the capability for this level of care?' I would ensure the patient and family are informed about their right to participate in facility selection.","Transfer facility capability advocacy.","intermediate"),
  q("sq-bg15-125",cn,"career_advancement","You want to create a meaningful nursing career.","What makes a nursing career fulfilling?","A fulfilling nursing career combines: clinical competence that builds confidence, meaningful patient connections, continuous learning and growth, work-life balance, supportive relationships with colleagues, alignment between personal values and work, contribution to the profession through mentorship and advocacy, and the knowledge that your work genuinely matters in people's lives.","Nursing career fulfillment components.","beginner"),
  q("sq-bg15-126",ip,"clinical_judgment","A patient develops propofol infusion syndrome.","What is propofol infusion syndrome?","PRIS is a rare but fatal complication of prolonged high-dose propofol infusion (>4mg/kg/hr for >48 hours). It presents with metabolic acidosis, rhabdomyolysis, hyperkalemia, hepatomegaly, cardiac failure, and lipemia. I would monitor triglycerides and CK during propofol infusions, limit doses, and consider alternative sedation for prolonged ICU stays.","Propofol infusion syndrome dose monitoring.","advanced"),
  q("sq-bg15-127",ws,"patient_safety","A patient develops severe sepsis.","How would you implement the sepsis bundle?","Hour-1 sepsis bundle: measure lactate, obtain blood cultures before antibiotics, administer broad-spectrum antibiotics within 1 hour, begin 30mL/kg crystalloid for hypotension or lactate ≥4, and apply vasopressors if hypotensive after fluid resuscitation to maintain MAP ≥65. Each hour of antibiotic delay increases mortality by 7.6%. Compliance with the complete bundle significantly improves survival.","Sepsis hour-1 bundle implementation.","intermediate"),
  q("sq-bg15-128",ct,"time_management","You are struggling to eat during your shift.","How would you ensure adequate nutrition during shifts?","I would pack nutritious, easy-to-eat meals and snacks, coordinate with colleagues for break coverage, prioritize eating during natural workflow breaks (after medication passes, during patient meals), and advocate for protected break time with the charge nurse. Skipping meals impairs cognitive function, increases error risk, and contributes to long-term health problems. My patients need a nourished nurse.","Shift nutrition planning for safety.","beginner"),
  q("sq-bg15-129",pd,"ethical_dilemmas","A pharmaceutical company offers to sponsor a unit education event.","How would you evaluate pharmaceutical sponsorship?","I would consider: does the sponsorship create bias in prescribing? Is the educational content evidence-based and balanced? Does the facility policy allow pharmaceutical sponsorship? Are there alternative funding sources? I would ensure any sponsored education includes disclosures and presents balanced information about all treatment options, not just the sponsor's product.","Pharmaceutical sponsorship critical evaluation.","intermediate"),
  q("sq-bg15-130",cn,"career_advancement","You want to understand population health nursing.","What is population health nursing?","Population health nursing focuses on improving health outcomes for defined populations rather than individual patients: epidemiological surveillance, community health assessments, program development, policy advocacy, and health equity promotion. Roles include: public health nurse, community health worker supervisor, epidemiologist, and health department leadership. The COVID pandemic highlighted the critical importance of population health infrastructure.","Population health nursing overview.","intermediate"),
  q("sq-bg15-131",ip,"clinical_judgment","A patient develops Addisonian crisis from steroid withdrawal.","What precipitates Addisonian crisis?","Addisonian crisis is triggered by: abrupt steroid discontinuation, physiological stress in patients with adrenal insufficiency, or bilateral adrenal destruction. It presents with severe hypotension, hyperkalemia, hyponatremia, hypoglycemia, and cardiovascular collapse. Never stop long-term steroids abruptly—always taper. I would administer IV hydrocortisone 100mg immediately and aggressive fluid resuscitation.","Steroid withdrawal crisis prevention.","advanced"),
  q("sq-bg15-132",ws,"interdisciplinary_communication","A home health nurse calls with concerns about a recently discharged patient.","How would you coordinate with home health about a discharged patient?","I would listen to the concerns, review the discharge documentation, communicate the information to the patient's physician, facilitate any needed medication or care plan changes, and ensure the home health nurse has the contact information for the patient's outpatient team. Post-discharge communication between inpatient and home health teams prevents readmissions.","Home health post-discharge coordination.","beginner"),
  q("sq-bg15-133",ct,"documentation_challenges","You need to document a patient's advance directive changes.","How would you document advance directive updates?","I would document: 'Patient initiated discussion about changing code status from full code to DNR/DNI. Patient demonstrates capacity for this decision. Specific wishes discussed: no CPR, no intubation, no mechanical ventilation. Comfort measures preferred. Healthcare proxy remains [name]. Physician Dr. [name] notified and new order entered. Copy of updated AD placed in chart. Family aware and supportive.'","Advance directive update documentation.","intermediate"),
  q("sq-bg15-134",pd,"patient_communication","A patient asks if they are going to die.","How would you respond when a patient asks if they will die?","I would be honest and compassionate: 'That is an important question and shows courage. Your medical team is doing everything possible to help you. From what I see, [honest clinical observation]. I think the most important thing is to talk with your physician about your prognosis so you have the information you need to make decisions that matter to you.'","Death question honest compassionate response.","intermediate"),
  q("sq-bg15-135",cn,"career_advancement","You want to understand the importance of nursing research.","How does nursing research impact patient care?","Nursing research directly improves patient outcomes by: establishing evidence-based protocols, developing better assessment tools, improving patient education methods, identifying system-level safety improvements, and advancing the science of nursing care. Every nurse benefits from research—even bedside nurses can participate through quality improvement projects, data collection, and implementing evidence-based changes.","Nursing research practical impact.","beginner"),
  q("sq-bg15-136",ip,"clinical_judgment","A patient develops cauda equina syndrome.","What is cauda equina syndrome?","Cauda equina syndrome is compression of nerve roots below the conus medullaris presenting with: saddle anesthesia, bowel and bladder dysfunction (urinary retention or incontinence), bilateral leg weakness, and severe low back pain. This is a surgical emergency—delayed decompression within 24-48 hours leads to permanent neurological deficit. I would arrange emergent MRI and neurosurgical consultation.","Cauda equina surgical emergency recognition.","advanced"),
  q("sq-bg15-137",ws,"patient_safety","A patient on an insulin pump is admitted.","How would you manage a patient's personal insulin pump in the hospital?","I would verify the pump settings with the endocrinologist, determine if the patient should continue self-managing the pump or transition to hospital-managed insulin, ensure the patient is capable of managing the pump independently, document pump settings and any changes, and have backup subcutaneous insulin orders in case of pump malfunction.","Insulin pump inpatient management coordination.","intermediate"),
  q("sq-bg15-138",ct,"critical_thinking_drills","A patient's platelet count is 25,000.","When does severe thrombocytopenia require platelet transfusion?","Platelet count of 25,000 (normal 150,000-400,000) represents severe thrombocytopenia. Transfusion thresholds: <10,000 for prophylaxis in stable patients, <20,000 with fever or planned procedures, <50,000 for active bleeding or invasive procedures, and <100,000 for neurosurgery. I would implement bleeding precautions, avoid IM injections and rectal procedures, and investigate the cause.","Platelet transfusion threshold stratification.","intermediate"),
  q("sq-bg15-139",pd,"advocacy","A patient needs durable medical equipment but faces bureaucratic delays.","How would you expedite DME procurement?","I would contact the DME company directly, escalate through case management, ensure all physician orders and supporting documentation are complete and submitted, advocate for emergency or expedited processing, explore loaner equipment from the hospital or community, and ensure the patient has a safe interim plan while awaiting the equipment.","DME procurement delay advocacy.","beginner"),
  q("sq-bg15-140",cn,"career_advancement","You want to leave a positive impact on the next generation of nurses.","How would you contribute to nursing's future?","I would mentor students and new graduates, participate in nursing education, advocate for system improvements, contribute to nursing research, support workplace wellness initiatives, serve on professional committees, and maintain the highest standards of patient care. The strongest legacy any nurse can leave is a generation of competent, compassionate nurses they helped develop.","Nursing legacy through mentorship and advocacy.","beginner"),
];
